```c++
class Solution {
public:
    int maxTaskAssign(vector<int>& tasks, vector<int>& workers, int pills, int strength) {
        sort(tasks.begin(), tasks.end());
        sort(workers.begin(), workers.end());
        int taskCount = 0;
        int workerIndex = 0;
        for (int i = 0; i < tasks.size(); i++) {
            if (workerIndex < workers.size() && workers[workerIndex] >= tasks[i]) {
                taskCount++;
                workerIndex++;
            } else if (pills > 0) {
                workers[workerIndex] += strength;
                taskCount++;
                pills--;
                workerIndex++;
            }
        }
        return taskCount;
    }
};
```

